SELECT regulation_name, description 
FROM regulations 
WHERE regulation_id = 1;

SELECT DISTINCT UPPER(violation_type) AS unique_violation_type
FROM violations
ORDER BY unique_violation_type;

SELECT violation_type 
FROM violations 
WHERE total_count = (SELECT MAX(total_count) FROM violations);

SELECT job_title
FROM compliance_officers
WHERE strftime('%Y', start_date) IN ('2017', '2018');

SELECT 
  (SELECT COUNT(*) FROM compliance_officers) AS number_of_officers,
  (SELECT COUNT(*) FROM corrective_actions) AS total_corrective_actions;
